// KEIS 搶單通知：收 grab.py POST 進來的 payload，組成 LINE 訊息
const body = $input.first().json.body || $input.first().json;
const USER_ID = "Ufab42c56b2eb9b9a9ff18c367b85a6dd"; // 薛力瑜

let text;
if (body.event === 'alert') {
  text = body.text || '⚠ KEIS 搶單警示';
} else {
  const g = body.grabbed || [];
  const lines = g.map(x => `・${x.name} ${x.phone}｜${x.city} ${x.category} ${x.budget}`).join('\n');
  const left = (body.quota_left != null) ? body.quota_left : '?';
  // 今日累計（舊版 grab.py 沒帶這兩欄時退回用本批數量）
  const newToday = (body.new_today != null) ? body.new_today : g.length;
  const grabbedToday = (body.grabbed_today != null) ? body.grabbed_today : g.length;
  const missed = newToday - grabbedToday;
  const hint = missed > 0 ? `⚠ 有 ${missed} 筆沒搶到（搶輸/配額滿）` : '✅ 出的全搶到';
  text = `🎯 KEIS 這批搶到 ${g.length} 筆\n📊 今天累計 新名單 ${newToday} ／ 搶到 ${grabbedToday}｜剩餘配額 ${left}\n${hint}\n\n${lines}`;
}
return [{ json: { userId: USER_ID, text } }];
